issue_body:
I'm using glad in a file that get's compiled as a shared object library. When
I dynamically load a function from that library and call it, I get a segfault.

This segfault occurs only when the dynamically loaded function contains calls to
OpenGL functions that have been loaded by glad. If I use Glew, rather than glad,
in the library, the program works as expected.


## Example

I have tried to make a reasonably minimal example that reproduces the problem.
A glfw-provided window is opened, a function is dynamically loaded from
`lib.so` with `dlopen()` and `dlsym()`, and that function is called. The
function just clears the screen to blue.

When glad is used, a segfault is thrown during the call to `glClearColor()`.


### Steps to Reproduce

1. `$ chmod +x build.sh && ./build.sh && ./main`
2. See segfault
3. Uncomment the commented out lines in `build.sh`
4. `$ .build.sh && ./main`
5. See a nice blue screen, as intended


### Structure

```
.
├── build.sh
├── include
│   ├── glad
│   │   └── glad.h
│   └── KHR
│       └── khrplatform.h
└── src
    ├── glad.c
    ├── lib.c
    └── main.c

4 directories, 6 files
```


### build.sh

```bash
#/usr/bin/sh

gcc -std=c99 -Iinclude -Wall -Wextra -Wshadow \
    src/main.c src/glad.c -o main \
    -ldl -lglfw -lGL


gcc -std=c99 -Iinclude -Wall -Wextra -Wshadow -fpic -shared \
    src/lib.c src/glad.c -o lib.so \
    -ldl -lglfw -lGL

# building the library with GLEW fixes the problem
#gcc -std=c99 -Wall -Wextra -Wshadow -fpic -shared \
#    -DUSE_GLEW \
#    src/lib.c -o lib.so \
#    -ldl -lglfw -lGL -lGLEW
```


### src/glad.c

```c
/*

    OpenGL loader generated by glad 0.1.24a0 on Thu May 31 07:06:52 2018.

    Language/Generator: C/C++
    Specification: gl
    APIs: gl=3.3
    Profile: compatibility
    Extensions:
        
    Loader: True
    Local files: False
    Omit khrplatform: False

    Commandline:
        --profile="compatibility" --api="gl=3.3" --generator="c" --spec="gl" --extensions=""
    Online:
        http://glad.dav1d.de/#profile=compatibility&language=c&specification=gl&loader=on&api=gl%3D3.3
*/

// ...
```


### src/lib.c

```c
#ifdef USE_GLEW
#include <GL/glew.h>
#else
#include <glad/glad.h>
#endif

void draw_blue_screen()
{
    glClearColor(0.0f, 0.0f, 1.0f, 1.0f);
    glClear(GL_COLOR_BUFFER_BIT);
}
```


### src/main.c

```c
#include <stdio.h>
#include <stddef.h>
#include <dlfcn.h>

#include <glad/glad.h>
#include <GLFW/glfw3.h>

typedef void (draw_blue_screen_func)(void);

int main(void)
{
    if (!glfwInit())
    {
        fprintf(stderr, "GLFW initialization failed\n");
        return -1;
    }

    glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3);
    glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3);
    glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);
    glfwWindowHint(GLFW_RESIZABLE, GL_FALSE);

    GLFWwindow* window = glfwCreateWindow(800, 600, "example", NULL, NULL);
    if (!window)
    {
        fprintf(stderr, "GLFW window creation failed\n");
        glfwTerminate();
        return -1;
    }
    glfwMakeContextCurrent(window);

    if (!gladLoadGLLoader((GLADloadproc) glfwGetProcAddress))
    {
        fprintf(stderr, "glad initialization failed\n");
        glfwDestroyWindow(window);
        glfwTerminate();
        return -1;
    }

    // Dynamically load a function from lib.so
    void *lib_code = dlopen("./lib.so", RTLD_LAZY);
    draw_blue_screen_func *draw_blue_screen = (draw_blue_screen_func *) dlsym(lib_code, "draw_blue_screen");

    uint64_t frame_number = 0;
    while (!glfwWindowShouldClose(window))
    {
        printf("Frame %" PRIu64 "\n", frame_number);

        draw_blue_screen();

        glfwSwapBuffers(window);
        glfwPollEvents();
        frame_number++;
    }

    glfwDestroyWindow(window);
    glfwTerminate();
    return 0;
}
```

Why the value of self.count is changeless on the condition that the id(self.count) share the same memory address???

Source code:

from pyspider.libs.base_handler import *

class Handler(BaseHandler):
    crawl_config = {
    }

    def __init__(self,):
        self.count = 1
    
    @every(minutes=24 * 60)
    def on_start(self):
        self.crawl('http://www.baidu.com', callback=self.index_page)

    @config(age=10 * 24 * 60 * 60)
    def index_page(self, response):

        self.count += 1
        print id(self.count),
        print self.count
        
        for each in response.doc('a[href^="http"]').items():
            self.crawl(each.attr.href, callback=self.index_page)
            break

<img width="978" alt="9aec0aaf-0c15-432e-a3bd-cdee5eabbb88" src="https://cloud.githubusercontent.com/assets/2860999/24748024/e4e258aa-1af0-11e7-9e6a-26a907c75405.png">

[`png_loader.h`](https://github.com/davisking/dlib/blob/master/dlib/image_loader/png_loader.h) which has functions called for `load_png()` contains the following code for loading 16-bit grayscale png:

```
else if (is_graya() && bit_depth_ == 16)
            {
                for ( unsigned n = 0; n < height_;n++ )
                {
                    const uint16* v = (uint16*)get_row( n );
                    for ( unsigned m = 0; m < width_; m++ )
                    {
                        dlib::uint16 p = v[m*2];
                        if (!pixel_traits<pixel_type>::has_alpha)
                        {
                            assign_pixel( t[n][m], p );
                        }
                        else
                        {
                            dlib::uint16 pa = v[m*2+1];
                            rgb_alpha_pixel pix;
                            assign_pixel(pix, p);
                            assign_pixel(pix.alpha, pa);
                            assign_pixel(t[n][m], pix);
                        }
                    }
                }
}
```

But `rgb_alpha_pixel ` according to [`pixel.h`](https://github.com/davisking/dlib/blob/master/dlib/pixel.h) is 

```
unsigned char red;
unsigned char green;
unsigned char blue;
unsigned char alpha;
```

So when I'm loading the image where all the values are multiplied by 255, `save_png` then saves empty white output.

I've seen that `is_rgb() && bit_depth_ == 16` is converted to 8-bit below, so if 16-bit is unsupported then the code above can also convert to 8-bit (`matrix<rgb_alpha_pixel>` works fine for me).

Or do I miss something about it?

In on_close method

    @tornado.gen.coroutine
    def on_close(self):
         if self.client.subscribed:
             print (yield self.client.pubsub_unsubscribe())
             print 'test'

Will not print 'test' for me. Everything after `pubsub_unsubscribe` with no arguments doesn't seem to run, though it should unsubscribe all channels.
But if I use pubsub_unsubscribe with a channel it seems to work.

